import{_ as e,o as r,c as o,ag as t}from"./chunks/framework.BZohXCq9.js";const s=JSON.parse('{"title":"bamdra-memory-vector","description":"Bamdra OpenClaw 套件中语义召回插件 bamdra-memory-vector 的产品介绍。","frontmatter":{"title":"bamdra-memory-vector","description":"Bamdra OpenClaw 套件中语义召回插件 bamdra-memory-vector 的产品介绍。"},"headers":[],"relativePath":"zh/guide/memory-vector.md","filePath":"zh/guide/memory-vector.md","lastUpdated":null}'),m={name:"zh/guide/memory-vector.md"};function l(i,a,d,c,n,h){return r(),o("div",null,[...a[0]||(a[0]=[t('<h1 id="bamdra-memory-vector" tabindex="-1">bamdra-memory-vector <a class="header-anchor" href="#bamdra-memory-vector" aria-label="Permalink to &quot;bamdra-memory-vector&quot;">​</a></h1><p><code>bamdra-memory-vector</code> 是 Bamdra OpenClaw 套件里的语义召回插件，而且也可以独立运行。</p><h2 id="它解决什么问题" tabindex="-1">它解决什么问题 <a class="header-anchor" href="#它解决什么问题" aria-label="Permalink to &quot;它解决什么问题&quot;">​</a></h2><p><code>bamdra-openclaw-memory</code> 擅长连续性，<code>bamdra-memory-vector</code> 补的是轻量语义召回。当用户用模糊表达、关键词不完整、或者隔了很久重新回来时，它能更稳地把相关内容找回来。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li>Markdown 可读记忆</li><li>本地语义索引</li><li>按用户边界隔离检索</li><li>面向长程记忆的 Top-K 召回</li></ul><h2 id="为什么重要" tabindex="-1">为什么重要 <a class="header-anchor" href="#为什么重要" aria-label="Permalink to &quot;为什么重要&quot;">​</a></h2><p>很多团队希望有语义检索能力，但不想额外部署一个重型向量数据库。这个插件的价值就在于：它把增强保持在本地、轻量、可读、易维护的范围内。</p><h2 id="它和其他插件的关系" tabindex="-1">它和其他插件的关系 <a class="header-anchor" href="#它和其他插件的关系" aria-label="Permalink to &quot;它和其他插件的关系&quot;">​</a></h2><ul><li>可以单独作为本地检索插件运行</li><li>配合 <code>bamdra-openclaw-memory</code> 时是可选增强</li><li>它不是用来替代 continuity-first 主记忆运行时的</li></ul><h2 id="仓库" tabindex="-1">仓库 <a class="header-anchor" href="#仓库" aria-label="Permalink to &quot;仓库&quot;">​</a></h2><ul><li>GitHub: <a href="https://github.com/bamdra/bamdra-memory-vector" target="_blank" rel="noreferrer">bamdra/bamdra-memory-vector</a></li><li>全部仓库入口: <a href="https://github.com/bamdra" target="_blank" rel="noreferrer">github.com/bamdra</a></li></ul>',12)])])}const u=e(m,[["render",l]]);export{s as __pageData,u as default};
